import React, { createContext, useState, useContext, useEffect } from 'react';

// Création du contexte
const AuthContext = createContext();

// Hook pour utiliser le contexte dans d'autres composants
export const useAuth = () => useContext(AuthContext);

// Fournisseur du contexte
const AuthProvider = ({ children }) => {
  // Vérifiez le localStorage pour voir si l'utilisateur est déjà authentifié
  const [isAuthenticated, setIsAuthenticated] = useState(() => {
    const storedAuthStatus = localStorage.getItem("isAuthenticated");
    return storedAuthStatus === "true"; // Si l'utilisateur est authentifié dans le localStorage
  });

  const login = () => {
    setIsAuthenticated(true);
    localStorage.setItem("isAuthenticated", "true"); // Mettez à jour le localStorage
  };

  const logout = () => {
    setIsAuthenticated(false);
    localStorage.setItem("isAuthenticated", "false"); // Mettez à jour le localStorage
  };

  useEffect(() => {
    // Mettez à jour le localStorage à chaque changement de l'état d'authentification
    localStorage.setItem("isAuthenticated", isAuthenticated.toString());
  }, [isAuthenticated]);

  return (
    <AuthContext.Provider value={{ isAuthenticated, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export default AuthProvider;
